    pair<int, int> goal = {-1, -1};
    for (int row = 0; row < static_cast<int>(grid.size()); ++row) {
        for (int col = 0; col < static_cast<int>(grid[row].size()); ++col) {
            if (grid[row][col] == 'S') start = {row, col};
            if (grid[row][col] == 'E') goal = {row, col};
