def normalize_query_094(query):
    latest = {}
    for part in query.replace(";", "&").split("&"):
        if "=" not in part:
            continue
        key, value = part.split("=", 1)
        key = key.strip().lower()
        value = value.strip().lower()
        if key and value:
            latest[key] = value
    return "&".join(f"{key}={latest[key]}" for key in sorted(latest))

