#include <vector>
using namespace std;
int bit_balance_score_250(const vector<int>& values) {
    int score = 0;
    for (int value : values) {
        int bits = __builtin_popcount(static_cast<unsigned int>(abs(value)));
        if (value % 2 == 0) score += bits;
        else score -= bits;
    }
    return score;
}

